/**
 * Notification log model — represents a historical record of a sent notification.
 *
 * Captures: recipient, channel, type, timestamp, and delivery status.
 */

import type { NotificationChannel, NotificationType } from './notification.js';

export type DeliveryStatus = 'sent' | 'failed' | 'suppressed';

export interface NotificationLogEntry {
  id: string;
  notificationId: string;
  recipient: string;
  channel: NotificationChannel;
  type: NotificationType;
  subject: string;
  status: DeliveryStatus;
  error?: string;
  timestamp: Date;
  deliveredAt?: Date;
  metadata?: Record<string, string>;
}

export interface NotificationHistoryQuery {
  recipient?: string;
  type?: NotificationType;
  channel?: NotificationChannel;
  status?: DeliveryStatus;
  from?: Date;
  to?: Date;
}

/**
 * Notification history service — logs and queries sent notification records.
 *
 * Every notification dispatched by NotificationService is logged here,
 * including suppressed notifications. Supports querying by recipient,
 * type, channel, status, and date range.
 */

import type {
  NotificationLogEntry,
  NotificationHistoryQuery,
  DeliveryStatus,
} from '../models/notification-log.js';
import type { NotificationChannel, NotificationType } from '../models/notification.js';

let nextLogId = 1;

function generateLogId(): string {
  return `log-${String(nextLogId++).padStart(4, '0')}`;
}

export function resetLogIdCounter(): void {
  nextLogId = 1;
}

export class NotificationHistoryService {
  private entries: NotificationLogEntry[] = [];

  log(params: {
    notificationId: string;
    recipient: string;
    channel: NotificationChannel;
    type: NotificationType;
    subject: string;
    status: DeliveryStatus;
    error?: string;
    deliveredAt?: Date;
    metadata?: Record<string, string>;
  }): NotificationLogEntry {
    const entry: NotificationLogEntry = {
      id: generateLogId(),
      notificationId: params.notificationId,
      recipient: params.recipient,
      channel: params.channel,
      type: params.type,
      subject: params.subject,
      status: params.status,
      error: params.error,
      timestamp: new Date(),
      deliveredAt: params.deliveredAt,
      metadata: params.metadata,
    };

    this.entries.push(entry);
    return entry;
  }

  query(filter: NotificationHistoryQuery): NotificationLogEntry[] {
    return this.entries.filter((entry) => {
      if (filter.recipient !== undefined && entry.recipient !== filter.recipient) {
        return false;
      }
      if (filter.type !== undefined && entry.type !== filter.type) {
        return false;
      }
      if (filter.channel !== undefined && entry.channel !== filter.channel) {
        return false;
      }
      if (filter.status !== undefined && entry.status !== filter.status) {
        return false;
      }
      if (filter.from !== undefined && entry.timestamp < filter.from) {
        return false;
      }
      if (filter.to !== undefined && entry.timestamp > filter.to) {
        return false;
      }
      return true;
    });
  }

  getByRecipient(recipient: string): NotificationLogEntry[] {
    return this.entries.filter((e) => e.recipient === recipient);
  }

  getByType(type: NotificationType): NotificationLogEntry[] {
    return this.entries.filter((e) => e.type === type);
  }

  getByDateRange(from: Date, to: Date): NotificationLogEntry[] {
    return this.entries.filter((e) => e.timestamp >= from && e.timestamp <= to);
  }

  getAll(): NotificationLogEntry[] {
    return [...this.entries];
  }

  getCount(): number {
    return this.entries.length;
  }

  clear(): void {
    this.entries = [];
  }
}

