import { describe, it, expect, beforeEach } from 'vitest';
import {
  NotificationHistoryService,
  resetLogIdCounter,
} from '../../src/services/notification-history.service.js';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { PreferencesService } from '../../src/services/preferences.service.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

describe('NotificationHistoryService', () => {
  let historyService: NotificationHistoryService;

  beforeEach(() => {
    historyService = new NotificationHistoryService();
    resetLogIdCounter();
  });

  describe('log', () => {
    it('should create a log entry with sequential IDs', () => {
      const entry = historyService.log({
        notificationId: 'notif-0001',
        recipient: 'alice@example.com',
        channel: 'email',
        type: 'order_confirmation',
        subject: 'Order Confirmation',
        status: 'sent',
        deliveredAt: new Date(),
      });

      expect(entry.id).toBe('log-0001');
      expect(entry.recipient).toBe('alice@example.com');
      expect(entry.channel).toBe('email');
      expect(entry.type).toBe('order_confirmation');
      expect(entry.status).toBe('sent');
      expect(entry.timestamp).toBeInstanceOf(Date);
    });

    it('should log failed notifications with error', () => {
      const entry = historyService.log({
        notificationId: 'notif-0001',
        recipient: 'alice@example.com',
        channel: 'email',
        type: 'order_confirmation',
        subject: 'Order Confirmation',
        status: 'failed',
        error: 'Transport error',
      });

      expect(entry.status).toBe('failed');
      expect(entry.error).toBe('Transport error');
    });

    it('should log suppressed notifications', () => {
      const entry = historyService.log({
        notificationId: 'notif-0001',
        recipient: 'alice@example.com',
        channel: 'email',
        type: 'order_confirmation',
        subject: 'Order Confirmation',
        status: 'suppressed',
      });

      expect(entry.status).toBe('suppressed');
    });

    it('should preserve metadata', () => {
      const entry = historyService.log({
        notificationId: 'notif-0001',
        recipient: 'alice@example.com',
        channel: 'email',
        type: 'order_confirmation',
        subject: 'Order Confirmation',
        status: 'sent',
        metadata: { orderId: 'order-123' },
      });

      expect(entry.metadata).toEqual({ orderId: 'order-123' });
    });
  });

  describe('query', () => {
    beforeEach(() => {
      historyService.log({
        notificationId: 'notif-0001',
        recipient: 'alice@example.com',
        channel: 'email',
        type: 'order_confirmation',
        subject: 'Order Confirmation',
        status: 'sent',
      });
      historyService.log({
        notificationId: 'notif-0002',
        recipient: 'bob@example.com',
        channel: 'webhook',
        type: 'order_status_update',
        subject: 'Order Update',
        status: 'sent',
      });
      historyService.log({
        notificationId: 'notif-0003',
        recipient: 'alice@example.com',
        channel: 'email',
        type: 'welcome',
        subject: 'Welcome',
        status: 'failed',
        error: 'Invalid address',
      });
    });

    it('should query by recipient', () => {
      const results = historyService.query({ recipient: 'alice@example.com' });
      expect(results).toHaveLength(2);
      expect(results.every((e) => e.recipient === 'alice@example.com')).toBe(true);
    });

    it('should query by type', () => {
      const results = historyService.query({ type: 'order_confirmation' });
      expect(results).toHaveLength(1);
      expect(results[0]?.type).toBe('order_confirmation');
    });

    it('should query by channel', () => {
      const results = historyService.query({ channel: 'webhook' });
      expect(results).toHaveLength(1);
      expect(results[0]?.recipient).toBe('bob@example.com');
    });

    it('should query by status', () => {
      const results = historyService.query({ status: 'failed' });
      expect(results).toHaveLength(1);
      expect(results[0]?.error).toBe('Invalid address');
    });

    it('should combine multiple filters', () => {
      const results = historyService.query({
        recipient: 'alice@example.com',
        status: 'sent',
      });
      expect(results).toHaveLength(1);
      expect(results[0]?.type).toBe('order_confirmation');
    });

    it('should return all entries with empty filter', () => {
      const results = historyService.query({});
      expect(results).toHaveLength(3);
    });

    it('should filter by date range', () => {
      const now = new Date();
      const past = new Date(now.getTime() - 60000);
      const future = new Date(now.getTime() + 60000);

      const results = historyService.query({ from: past, to: future });
      expect(results).toHaveLength(3);

      const noResults = historyService.query({
        from: new Date(now.getTime() + 60000),
        to: new Date(now.getTime() + 120000),
      });
      expect(noResults).toHaveLength(0);
    });
  });

  describe('convenience methods', () => {
    beforeEach(() => {
      historyService.log({
        notificationId: 'notif-0001',
        recipient: 'alice@example.com',
        channel: 'email',
        type: 'order_confirmation',
        subject: 'Order Confirmation',
        status: 'sent',
      });
      historyService.log({
        notificationId: 'notif-0002',
        recipient: 'bob@example.com',
        channel: 'email',
        type: 'order_confirmation',
        subject: 'Order Confirmation',
        status: 'sent',
      });
    });

    it('should get by recipient', () => {
      expect(historyService.getByRecipient('alice@example.com')).toHaveLength(1);
      expect(historyService.getByRecipient('nobody@example.com')).toHaveLength(0);
    });

    it('should get by type', () => {
      expect(historyService.getByType('order_confirmation')).toHaveLength(2);
      expect(historyService.getByType('welcome')).toHaveLength(0);
    });

    it('should get by date range', () => {
      const now = new Date();
      const results = historyService.getByDateRange(
        new Date(now.getTime() - 60000),
        new Date(now.getTime() + 60000),
      );
      expect(results).toHaveLength(2);
    });

    it('should get all entries as a copy', () => {
      const all = historyService.getAll();
      expect(all).toHaveLength(2);
    });

    it('should get count', () => {
      expect(historyService.getCount()).toBe(2);
    });

    it('should clear all entries', () => {
      historyService.clear();
      expect(historyService.getCount()).toBe(0);
    });
  });

  describe('integration with NotificationService', () => {
    let eventBus: EventBus;
    let notificationService: NotificationService;

    beforeEach(() => {
      eventBus = new EventBus();
      resetNotificationIdCounter();
      notificationService = new NotificationService(eventBus, undefined, historyService);
    });

    it('should log sent notifications', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
          total: 20,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const history = historyService.getAll();
      expect(history).toHaveLength(1);
      expect(history[0]?.recipient).toBe('alice@example.com');
      expect(history[0]?.channel).toBe('email');
      expect(history[0]?.type).toBe('order_confirmation');
      expect(history[0]?.status).toBe('sent');
      expect(history[0]?.notificationId).toBe('notif-0001');
    });

    it('should log status change notifications', async () => {
      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const history = historyService.getAll();
      expect(history).toHaveLength(1);
      expect(history[0]?.type).toBe('order_status_update');
      expect(history[0]?.status).toBe('sent');
    });

    it('should log suppressed notifications', async () => {
      const preferencesService = new PreferencesService();
      preferencesService.updatePreferences('user-1', {
        email: { enabled: false },
      });

      const serviceWithPrefs = new NotificationService(
        eventBus,
        preferencesService,
        historyService,
      );

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      // The original service should have no notifications (suppressed)
      expect(serviceWithPrefs.getNotificationCount()).toBe(0);

      // But history should have a suppressed entry
      const history = historyService.getAll();
      expect(history).toHaveLength(1);
      expect(history[0]?.status).toBe('suppressed');
      expect(history[0]?.recipient).toBe('alice@example.com');
    });

    it('should log multiple notifications and support querying', async () => {
      await eventBus.emit<OrderCreatedEvent>({
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      });

      await eventBus.emit<OrderStatusChangedEvent>({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 10,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      expect(historyService.getCount()).toBe(2);
      expect(historyService.query({ type: 'order_confirmation' })).toHaveLength(1);
      expect(historyService.query({ type: 'order_status_update' })).toHaveLength(1);
      expect(historyService.getByRecipient('alice@example.com')).toHaveLength(1);
      expect(historyService.getByRecipient('user-1')).toHaveLength(1);
    });
  });
});

